   205ŌåÆ// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   206ŌåÆfunc convertContents(req *model.LLMRequest) []chatMessage {
   207ŌåÆ	var msgs []chatMessage
   208ŌåÆ
   209ŌåÆ	// System instruction.
   210ŌåÆ	if req.Config != nil && req.Config.SystemInstruction != nil {
   211ŌåÆ		var text string
