   218ŌåÆ			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   219ŌåÆ		}
   220ŌåÆ	}
   221ŌåÆ
   222ŌåÆ	// Conversation contents.
   223ŌåÆ	for _, c := range req.Contents {
   224ŌåÆ		role := mapRole(c.Role)
   225ŌåÆ
   226ŌåÆ		// Check each part: could be text, function_call, or function_response.
   227ŌåÆ		for _, p := range c.Parts {
   228ŌåÆ			switch {
