   230ŌåÆ				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   231ŌåÆ				msgs = append(msgs, chatMessage{
   232ŌåÆ					Role: "assistant",
   233ŌåÆ					ToolCalls: []toolCall{{
   234ŌåÆ						ID:   p.FunctionCall.ID,
   235ŌåÆ						Type: "function",
   236ŌåÆ						Function: functionCall{
   237ŌåÆ							Name:      p.FunctionCall.Name,
   238ŌåÆ							Arguments: string(argsJSON),
