   161ŌåÆ
   162ŌåÆ	respReq := responsesRequest{
   163ŌåÆ		Model:        m.name,
   164ŌåÆ		Input:        items,
   165ŌåÆ		Instructions: instructions,
   166ŌåÆ		Tools:        tools,
   167ŌåÆ		Store:        false,
   168ŌåÆ	}
   169ŌåÆ
   170ŌåÆ	if req.Config != nil {
   171ŌåÆ		respReq.Temperature = req.Config.Temperature
