   174ŌåÆ			respReq.MaxTokens = req.Config.MaxOutputTokens
   175ŌåÆ		}
   176ŌåÆ	}
   177ŌåÆ
   178ŌåÆ	body, err := json.Marshal(respReq)
   179ŌåÆ	if err != nil {
   180ŌåÆ		return nil, fmt.Errorf("openai: marshal request: %w", err)
   181ŌåÆ	}
   182ŌåÆ
   183ŌåÆ	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/responses", bytes.NewReader(body))
   184ŌåÆ	if err != nil {
   185ŌåÆ		return nil, fmt.Errorf("openai: create http request: %w", err)
   186ŌåÆ	}
   187ŌåÆ	httpReq.Header.Set("Content-Type", "application/json")
   188ŌåÆ	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   189ŌåÆ
   190ŌåÆ	httpResp, err := m.client.Do(httpReq)
   191ŌåÆ	if err != nil {
   192ŌåÆ		return nil, fmt.Errorf("openai: http request: %w", err)
   193ŌåÆ	}
   194ŌåÆ	defer httpResp.Body.Close()
   195ŌåÆ
   196ŌåÆ	respBody, err := io.ReadAll(httpResp.Body)
   197ŌåÆ	if err != nil {
   198ŌåÆ		return nil, fmt.Errorf("openai: read response: %w", err)
   199ŌåÆ	}
   200ŌåÆ
   201ŌåÆ	if httpResp.StatusCode != http.StatusOK {
   202ŌåÆ		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   203ŌåÆ	}
   204ŌåÆ
   205ŌåÆ	var respOut responsesResponse
   206ŌåÆ	if err := json.Unmarshal(respBody, &respOut); err != nil {
   207ŌåÆ		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   208ŌåÆ	}
   209ŌåÆ
   210ŌåÆ	if respOut.Error != nil {
   211ŌåÆ		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   212ŌåÆ			respOut.Error.Message, respOut.Error.Type, respOut.Error.Code)
   213ŌåÆ	}
   214ŌåÆ
   215ŌåÆ	return convertResponseOutput(&respOut), nil
   216ŌåÆ}
