   218ŌåÆ// convertInputs transforms ADK Contents into Responses API input items and
   219ŌåÆ// extracts the system instruction as a separate instructions string.
   220ŌåÆfunc convertInputs(req *model.LLMRequest) ([]inputItem, string) {
   221ŌåÆ	var items []inputItem
   222ŌåÆ	var instructions string
   223ŌåÆ
   224ŌåÆ	// System instruction.
   225ŌåÆ	if req.Config != nil && req.Config.SystemInstruction != nil {
   226ŌåÆ		var text string
   227ŌåÆ		for _, p := range req.Config.SystemInstruction.Parts {
   228ŌåÆ			if p.Text != "" {
   229ŌåÆ				text += p.Text
   230ŌåÆ			}
   231ŌåÆ		}
   232ŌåÆ		instructions = text
   233ŌåÆ	}
   234ŌåÆ
   235ŌåÆ	// Conversation contents.
   236ŌåÆ	for _, c := range req.Contents {
   237ŌåÆ		for _, p := range c.Parts {
   238ŌåÆ			switch {
   239ŌåÆ			case p.FunctionCall != nil:
   240ŌåÆ				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   241ŌåÆ				items = append(items, inputItem{
   242ŌåÆ					Type:      "function_call",
   243ŌåÆ					CallID:    p.FunctionCall.ID,
   244ŌåÆ					Name:      p.FunctionCall.Name,
   245ŌåÆ					Arguments: string(argsJSON),
   246ŌåÆ				})
   247ŌåÆ			case p.FunctionResponse != nil:
   248ŌåÆ				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   249ŌåÆ				items = append(items, inputItem{
   250ŌåÆ					Type:   "function_call_output",
   251ŌåÆ					CallID: p.FunctionResponse.ID,
