type LLMConfig struct {
	Provider string // "gemini" or "openai"
	Model    string // e.g. "gemini-2.5-flash", "gpt-5.2"

	// Gemini
	GoogleAPIKey string

	// OpenAI
	OpenAIAPIKey      string
	OpenAIBaseURL     string // defaults to https://api.openai.com/v1
	OpenAISearchModel string // search-capable model for web search sub-agent
}

func NewLLMModel(ctx context.Context, cfg LLMConfig) (model.LLM, error) {
	switch cfg.Provider {
	case "gemini", "":
		if cfg.GoogleAPIKey == "" {
			return nil, fmt.Errorf("GOOGLE_API_KEY is required for gemini provider")
		}
		return gemini.NewModel(ctx, cfg.Model, &genai.ClientConfig{
			APIKey: cfg.GoogleAPIKey,
